using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1. Strongly-typed metadata — returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Type:       {personInfo.Type.Name}");
Console.WriteLine($"Kind:       {personInfo.Kind}");
Console.WriteLine($"Properties: {personInfo.Properties.Count}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person roundTripped = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Round-trip:  Name={roundTripped.Name}, Age={roundTripped.Age}");

Console.WriteLine();

// 2. Probe without throwing — TryGetTypeInfo returns false instead of throwing
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    Console.WriteLine($"Person metadata found (Kind={found!.Kind})");
}

// Use a source-gen-only context with no Person resolver, so Person is unknown
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine()   // empty composite — resolves nothing
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing))
{
    Console.WriteLine("Unexpected: metadata was found");
}
else
{
    Console.WriteLine("Person metadata NOT available (no exception thrown)");
}

public record Person(string Name, int Age);

